// Brain-coral / sea-coral decorative piece on a rounded rock base.
// Showcases v.sdf: a smoothUnion blob of ellipsoids made POROUS by
// intersecting a DIAMOND TPMS, sitting on a solid base slab.
const { voxels, sdf } = api;
const v = voxels();

const RES = 0.85; // world units per voxel

// --- Coral head: smoothUnion of several lobes forming a domed knobby mass ---
const lobeA = sdf.ellipsoid(15, 14, 12).translate([0, 0, 10]);
const lobeB = sdf.ellipsoid(10, 9, 13).translate([-9, -3, 16]);
const lobeC = sdf.ellipsoid(9, 11, 12).translate([10, 4, 15]);
const lobeD = sdf.ellipsoid(8, 8, 11).translate([2, 11, 17]);
const lobeE = sdf.ellipsoid(7, 8, 10).translate([-4, 9, 12]);

let head = lobeA
  .smoothUnion(lobeB, 5)
  .smoothUnion(lobeC, 5)
  .smoothUnion(lobeD, 4)
  .smoothUnion(lobeE, 4);

// --- Porosity: intersect a DIAMOND TPMS into the head ---
// Larger cell => bigger, clearly-visible holes. thickness ~0.95 keeps
// walls >=1 voxel. The porous shell is the visible knobby coral surface.
const porous = head.intersect(sdf.diamond(13, 0.75));

// --- Slim solid inner core + stem so the piece never fragments and bridges
// base, but small enough that the porous holes still read on the surface. ---
const core = sdf.ellipsoid(6, 6, 7).translate([0, 0, 10]);
const stem = sdf.cylinder(5, 18).translate([0, 0, 2]); // reaches down into base

// Coral solid = porous shell + solid inner core + stem.
const coral = porous.union(core).union(stem).label('coral');

// --- Rock base: a solid rounded slab flush at the bottom ---
const base = sdf.roundedCylinder(22, 8, 3).translate([0, 0, -2]).label('base');

const model = sdf.union(coral, base);

v.sdf(model, {
  res: RES,
  colors: { coral: '#ff7a6b', base: '#b9a37e' },
  color: '#ff7a6b',
});

// --- Weld to a single connected piece, then flat bottom ---
// v.keepLargest() drops any stray lattice specks so the coral prints as one
// piece (the solid core + stem already keep it connected, but this is belt-and-
// suspenders against parameter drift).
function flattenBottom(BASE) {
  const minz = new Map();
  v.forEach((x, y, z) => { const k = x + ',' + y; if (!minz.has(k) || z < minz.get(k)) minz.set(k, z); });
  for (const [k, z0] of minz) { const [x, y] = k.split(',').map(Number); for (let z = 0; z < z0; z++) v.set(x, y, z, BASE); }
}

v.keepLargest();
flattenBottom('#b9a37e');

return v;
